201→    /// 僅讀 metadata 取得尺寸（不解碼，portrait fit-to-width 時避免 thumbnail→fullRes 跳動）
202→    private static func readImageDimensions(at url: URL) -> CGSize? {
203→        guard !isPDFURL(url) else { return nil }
204→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else { return nil }
205→        guard let props = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as NSDictionary? else { return nil }
206→        let w = (props[kCGImagePropertyPixelWidth] as? NSNumber)?.intValue ?? 0
207→        let h = (props[kCGImagePropertyPixelHeight] as? NSNumber)?.intValue ?? 0
208→        guard w > 0, h > 0 else { return nil }
209→        return CGSize(width: w, height: h)
210→    }
211→
212→    /// 讀取圖片尺寸（不解碼完整圖片）用於 continuous scroll 模式
213→    /// - Parameter url: 圖片 URL
214→    /// - Returns: 圖片尺寸，已處理 EXIF orientation 5-8 的交換
215→    func getImageSize(for url: URL) async -> NSSize? {
216→        // PDF: 返回 nil（由其他邏輯處理）
217→        guard !Self.isPDFURL(url) else { return nil }
218→
219→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil),
220→              let props = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as? [String: Any] else {
221→            return nil
222→        }
223→
224→        let w = (props[kCGImagePropertyPixelWidth as String] as? CGFloat) ?? 0
225→        let h = (props[kCGImagePropertyPixelHeight as String] as? CGFloat) ?? 0
226→        guard w > 0, h > 0 else { return nil }
227→
228→        // 處理 EXIF orientation 5-8（90/270 度旋轉)
229→        // 這些 orientation 的 pixel dimensions 需要交換
230→        let orientation = (props[kCGImagePropertyOrientation as String] as? Int) ?? 1
231→        if orientation >= 5 && orientation <= 8 {
232→            return NSSize(width: h, height: w)
233→        }
234→        return NSSize(width: w, height: h)
235→    }
236→
237→    /// 使用 CGImageSourceCreateThumbnailAtIndex 快速解碼縮圖，同時讀取 full-res 尺寸
238→    /// 共用同一個 CGImageSource，避免二次開檔
239→    private static func decodeThumbnailWithDimensions(at url: URL, maxSize: CGFloat) -> (image: NSImage, fullSize: CGSize)? {
240→        guard !isPDFURL(url) else { return nil }
241→        let decodeStart = CFAbsoluteTimeGetCurrent()
242→
243→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else { return nil }
244→        let sourceMs = (CFAbsoluteTimeGetCurrent() - decodeStart) * 1000
245→
246→        // 讀 full-res dimensions（同一個 source，零額外 I/O）
247→        let fullSize: CGSize
248→        if let props = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as NSDictionary?,
249→           let w = (props[kCGImagePropertyPixelWidth] as? NSNumber)?.intValue,
250→           let h = (props[kCGImagePropertyPixelHeight] as? NSNumber)?.intValue,
251→           w > 0, h > 0 {
252→            fullSize = CGSize(width: w, height: h)
253→        } else {
254→            fullSize = .zero  // fallback: caller 會用 thumbnail size
255→        }
256→
257→        var options: [CFString: Any] = [
258→            kCGImageSourceCreateThumbnailFromImageAlways: true,
259→            kCGImageSourceCreateThumbnailWithTransform: true,
260→            kCGImageSourceThumbnailMaxPixelSize: maxSize,
261→        ]
262→        // Phase 3.1: SubsampleFactor for JPEG/HEIF DCT fast path at micro-thumbnail sizes
263→        let subsample: Int
264→        if maxSize <= Constants.quickGridSubsampleThresholdPx {
265→            subsample = 4
266→            options[kCGImageSourceSubsampleFactor] = subsample
267→        } else {
268→            subsample = 1
269→        }
270→        let thumbStart = CFAbsoluteTimeGetCurrent()
271→        guard let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, options as CFDictionary)
272→        else { return nil }
273→        let thumbMs = (CFAbsoluteTimeGetCurrent() - thumbStart) * 1000
274→
275→        let image = NSImage(cgImage: cgImage, size: NSSize(
276→            width: cgImage.width,
277→            height: cgImage.height
278→        ))
279→        let totalMs = (CFAbsoluteTimeGetCurrent() - decodeStart) * 1000
280→        GridPerfLog.log(String(format: "decode: total=%.2fms | source=%.2fms | thumb(%dx%d→%.0f,ss=%d)=%.2fms | %@",
281→                               totalMs, sourceMs, cgImage.width, cgImage.height, maxSize, subsample, thumbMs,
282→                               url.lastPathComponent))
283→
284→        let effectiveSize = fullSize == .zero ? image.size : fullSize
285→        return (image, effectiveSize)
286→    }
