303→    /// 預載用的圖片載入（支援 cooperative cancellation）
304→    private func loadImageCooperative(at url: URL) async -> NSImage? {
305→        if let cached = cache[url] { return cached }
306→        guard !Task.isCancelled else { return nil }
307→
308→        // 使用 Task 而非 Task.detached 以繼承 cancellation scope
309→        let image = await Task(priority: .userInitiated) { () -> NSImage? in
310→            guard !Task.isCancelled else { return nil }
311→            return Self.decodeImage(at: url)
312→        }.value
313→
314→        guard !Task.isCancelled else { return nil }
315→        if let image { cache[url] = image }
316→        return image
317→    }
